import React, { useState } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

function App() {
  // Brand Colors
  const gold = '#D4AF37';
  const deepTerracotta = '#8B311E'; // Rich, dark, expensive-looking terracotta

  // State to track which category is "Open"
  const [activeCategory, setActiveCategory] = useState('Small Chops');

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', margin: 0, padding: 0, fontFamily: 'Arial, sans-serif' }}>
      
      {/* 1. BRANDED NAVBAR */}
      <nav style={{ 
        display: 'flex', 
        flexDirection: 'column', // Stacked logo over menu for better visibility
        alignItems: 'center', 
        padding: '30px 20px', 
        backgroundColor: '#000', 
        borderBottom: `1px solid ${deepTerracotta}`
      }}>
        {/* LARGE LOGO */}
        <img src={Logo} alt="Àmí by T" style={{ 
          height: '120px', // Bigger and bolder
          width: 'auto',
          marginBottom: '20px',
          filter: 'contrast(130%) brightness(120%)',
          mixBlendMode: 'screen'
        }} />

        {/* NAVIGATION TABS (NO WHITE TEXT) */}
        <div style={{ display: 'flex', gap: '30px' }}>
          {['Small Chops', 'Office Lunch', 'Wigs', 'About Us'].map((item) => (
            <button 
              key={item} 
              onClick={() => setActiveCategory(item)}
              style={{ 
                background: 'none',
                border: 'none',
                color: activeCategory === item ? gold : deepTerracotta, // Gold if active, Terracotta if not
                fontSize: '0.9rem', 
                fontWeight: '600',
                letterSpacing: '1.5px',
                textTransform: 'uppercase',
                cursor: 'pointer',
                paddingBottom: '5px',
                borderBottom: activeCategory === item ? `2px solid ${gold}` : '2px solid transparent',
                transition: '0.3s'
              }}
            >
              {item}
            </button>
          ))}
        </div>
      </nav>

      {/* 2. DYNAMIC CONTENT SECTION */}
      <main style={{ padding: '40px 20px', maxWidth: '1200px', margin: '0 auto' }}>
        
        {/* CLICK-TO-VIEW LOGIC */}
        {activeCategory === 'Small Chops' && (
          <div className="fade-in">
            <h2 style={{ color: gold, textAlign: 'center', fontSize: '1.8rem', marginBottom: '30px' }}>Small Chops Collections</h2>
            <Menu />
          </div>
        )}

        {activeCategory === 'Office Lunch' && (
          <div className="fade-in">
            <h2 style={{ color: gold, textAlign: 'center', fontSize: '1.8rem', marginBottom: '30px' }}>Office Lunch Subscriptions</h2>
            <Lunch />
          </div>
        )}

        {activeCategory === 'Wigs' && (
          <div style={{ textAlign: 'center', padding: '100px 20px' }}>
            <h2 style={{ color: gold, fontSize: '1.8rem' }}>Affordable Wigs</h2>
            <p style={{ color: deepTerracotta }}>Premium Human Hair Collections Coming Soon...</p>
          </div>
        )}

        {activeCategory === 'About Us' && (
          <div style={{ textAlign: 'center', padding: '60px 20px', color: '#888' }}>
            <h2 style={{ color: gold }}>Taste & Style</h2>
            <p style={{ maxWidth: '600px', margin: '20px auto', lineHeight: '1.6' }}>
              Àmí by T is dedicated to providing premium small chops and office lunch solutions in Lagos.
            </p>
          </div>
        )}
      </main>

      {/* 3. FOOTER */}
      <footer style={{ textAlign: 'center', padding: '60px 40px', color: '#444', fontSize: '0.7rem' }}>
        <p style={{ letterSpacing: '4px', color: deepTerracotta }}>ÀMÍ BY T | LAGOS</p>
        <p style={{ marginTop: '10px' }}>© 2026 ALL RIGHTS RESERVED</p>
      </footer>

    </div>
  );
}

export default App;
